package com.tpcodl.powerpulse.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.DecimalMax;
import jakarta.validation.constraints.DecimalMin;
import lombok.*;
import org.hibernate.annotations.CreationTimestamp;

import java.time.LocalDate;
import java.time.LocalDateTime;

/**
 * Prediction entity — stores ML-generated failure probability predictions.
 * 
 * Generated by the Python ML service (FastAPI + XGBoost).
 * Each prediction estimates the probability of asset failure
 * within a specified time horizon (e.g., 30/60/90 days).
 * 
 * High-probability predictions (>0.7) trigger PREDICTIVE maintenance work orders.
 */
@Entity
@Table(name = "predictions", indexes = {
    @Index(name = "idx_pred_probability", columnList = "failure_probability"),
    @Index(name = "idx_pred_date", columnList = "predicted_failure_date")
})
@Getter @Setter
@NoArgsConstructor @AllArgsConstructor
@Builder
public class Prediction {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /** Human-readable prediction reference (e.g., "PRD-20260609-001") */
    @Column(name = "prediction_id", nullable = false, unique = true, length = 30)
    private String predictionId;

    /** Failure probability score (0.0 to 1.0) */
    @DecimalMin("0.0") @DecimalMax("1.0")
    @Column(name = "failure_probability", nullable = false)
    private Double failureProbability;

    /** Predicted date of failure if no action is taken */
    @Column(name = "predicted_failure_date")
    private LocalDate predictedFailureDate;

    /** Predicted failure mode (e.g., "Winding Insulation Breakdown", "Bushing Failure") */
    @Column(name = "failure_mode", length = 150)
    private String failureMode;

    /** Confidence score of the prediction model (0.0 to 1.0) */
    @Column(name = "confidence_score")
    private Double confidenceScore;

    /** ML model version used (e.g., "xgboost-v1.2.0") */
    @Column(name = "model_version", length = 50)
    private String modelVersion;

    /** Recommended action based on prediction (e.g., "Schedule preventive maintenance within 15 days") */
    @Column(name = "recommended_action", columnDefinition = "TEXT")
    private String recommendedAction;

    /** Time horizon in days for the prediction (e.g., 30, 60, 90) */
    @Column(name = "prediction_horizon_days")
    @Builder.Default
    private Integer predictionHorizonDays = 30;

    /** Whether a maintenance work order has been created based on this prediction */
    @Column(name = "action_taken", nullable = false)
    @Builder.Default
    private Boolean actionTaken = false;

    // ---- Audit Fields ----

    @CreationTimestamp
    @Column(name = "created_at", nullable = false, updatable = false)
    private LocalDateTime createdAt;

    // ---- Relationships ----

    /** The asset this prediction is for */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "asset_id", nullable = false)
    private Asset asset;
}
